const input = $input.first().json;
const action = input.action || 'list_files';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

// === Google OAuth Token Helper ===
async function getGoogleToken() {
  const creds = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&select=cred_key,cred_value',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const m = {};
  for (const c of creds) m[c.cred_key] = c.cred_value;

  if (!m.access_token || !m.refresh_token) {
    throw new Error('Google OAuth not configured. Install a Google skill and complete authorization first.');
  }

  if (new Date(m.token_expiry || 0) <= new Date(Date.now() + 5 * 60 * 1000)) {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://oauth2.googleapis.com/token',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'grant_type=refresh_token'
        + '&refresh_token=' + encodeURIComponent(m.refresh_token)
        + '&client_id=' + encodeURIComponent(m.client_id)
        + '&client_secret=' + encodeURIComponent(m.client_secret)
    });
    if (resp.error) throw new Error('Token refresh failed: ' + resp.error_description);

    const newExpiry = new Date(Date.now() + (resp.expires_in - 60) * 1000).toISOString();
    for (const [key, val] of [['access_token', resp.access_token], ['token_expiry', newExpiry]]) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.' + key, headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: key, cred_value: val }) });
    }
    if (resp.refresh_token) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.refresh_token', headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: 'refresh_token', cred_value: resp.refresh_token }) });
    }
    return resp.access_token;
  }
  return m.access_token;
}

let accessToken;
try {
  accessToken = await getGoogleToken();
} catch(e) {
  return [{ json: { error: e.message } }];
}

const gHeaders = {
  'Authorization': 'Bearer ' + accessToken,
  'Content-Type': 'application/json'
};
const DRIVE_BASE = 'https://www.googleapis.com/drive/v3';
const DRIVE_FIELDS = 'id,name,mimeType,size,modifiedTime,webViewLink,parents';

// === list_files ===
if (action === 'list_files') {
  const folderId = input.folder_id || 'root';
  const maxResults = parseInt(input.max_results) || 20;
  let q = "'" + folderId + "' in parents and trashed = false";
  if (input.query) {
    q += " and name contains '" + input.query.replace(/'/g, "\\'") + "'";
  }

  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: DRIVE_BASE + '/files?q=' + encodeURIComponent(q)
        + '&fields=files(' + DRIVE_FIELDS + ')'
        + '&pageSize=' + maxResults
        + '&orderBy=folder,name',
      headers: gHeaders
    });

    if (!resp.files || resp.files.length === 0) {
      return [{ json: { result: 'No files found in this folder.' } }];
    }

    let result = 'Files in folder (' + resp.files.length + ' items):\n\n';
    for (const f of resp.files) {
      const isFolder = f.mimeType === 'application/vnd.google-apps.folder';
      const icon = isFolder ? '[Folder]' : '[File]';
      const size = f.size ? ' (' + (parseInt(f.size) / 1024).toFixed(1) + ' KB)' : '';
      result += icon + ' ' + f.name + size + '\n';
      result += '  ID: ' + f.id + '\n';
      result += '  Modified: ' + (f.modifiedTime || '') + '\n';
      if (!isFolder) result += '  Type: ' + f.mimeType + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Failed to list files: ' + e.message } }];
  }

// === search_files ===
} else if (action === 'search_files') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];
  const maxResults = parseInt(input.max_results) || 20;
  const q = "name contains '" + query.replace(/'/g, "\\'") + "' and trashed = false";

  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: DRIVE_BASE + '/files?q=' + encodeURIComponent(q)
        + '&fields=files(' + DRIVE_FIELDS + ')'
        + '&pageSize=' + maxResults
        + '&orderBy=modifiedTime desc',
      headers: gHeaders
    });

    if (!resp.files || resp.files.length === 0) {
      return [{ json: { result: 'No files found matching "' + query + '".' } }];
    }

    let result = 'Search results for "' + query + '" (' + resp.files.length + ' files):\n\n';
    for (const f of resp.files) {
      const isFolder = f.mimeType === 'application/vnd.google-apps.folder';
      const icon = isFolder ? '[Folder]' : '[File]';
      const size = f.size ? ' (' + (parseInt(f.size) / 1024).toFixed(1) + ' KB)' : '';
      result += icon + ' ' + f.name + size + '\n';
      result += '  ID: ' + f.id + '\n';
      result += '  Type: ' + f.mimeType + '\n';
      result += '  Modified: ' + (f.modifiedTime || '') + '\n';
      if (f.webViewLink) result += '  Link: ' + f.webViewLink + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Search failed: ' + e.message } }];
  }

// === read_file ===
} else if (action === 'read_file') {
  const fileId = input.file_id;
  if (!fileId) return [{ json: { error: 'Parameter "file_id" is required.' } }];

  try {
    const meta = await helpers.httpRequest({
      method: 'GET',
      url: DRIVE_BASE + '/files/' + fileId + '?fields=' + DRIVE_FIELDS,
      headers: gHeaders
    });

    const mime = meta.mimeType || '';
    let content = '';
    let exported = false;

    // Google Workspace files: export
    const exportMap = {
      'application/vnd.google-apps.document': 'text/plain',
      'application/vnd.google-apps.spreadsheet': 'text/csv',
      'application/vnd.google-apps.presentation': 'text/plain'
    };

    if (exportMap[mime]) {
      const exportResp = await helpers.httpRequest({
        method: 'GET',
        url: DRIVE_BASE + '/files/' + fileId + '/export?mimeType=' + encodeURIComponent(exportMap[mime]),
        headers: { 'Authorization': 'Bearer ' + accessToken },
        encoding: 'utf-8',
        returnFullResponse: true
      });
      content = typeof exportResp.body === 'string' ? exportResp.body : JSON.stringify(exportResp.body);
      exported = true;
    } else if (mime.startsWith('application/vnd.google-apps.')) {
      // Other Google types (Drawing, Form, etc.) — no text export
      let result = '**' + meta.name + '** (Google Workspace file)\n';
      result += 'Type: ' + mime + '\n';
      result += 'This file type cannot be exported as text.\n';
      if (meta.webViewLink) result += 'View: ' + meta.webViewLink + '\n';
      return [{ json: { result } }];
    } else if (mime.startsWith('text/') || mime === 'application/json' || mime === 'application/xml'
      || mime === 'application/javascript' || mime === 'application/x-yaml'
      || mime.includes('csv') || mime.includes('markdown')) {
      // Text-based files: download inline
      const dlResp = await helpers.httpRequest({
        method: 'GET',
        url: DRIVE_BASE + '/files/' + fileId + '?alt=media',
        headers: { 'Authorization': 'Bearer ' + accessToken },
        encoding: 'utf-8',
        returnFullResponse: true
      });
      content = typeof dlResp.body === 'string' ? dlResp.body : JSON.stringify(dlResp.body);
    } else {
      // Binary files: return metadata + link
      let result = '**' + meta.name + '** (binary file)\n';
      result += 'Type: ' + mime + '\n';
      const size = meta.size ? (parseInt(meta.size) / 1024).toFixed(1) + ' KB' : 'unknown';
      result += 'Size: ' + size + '\n';
      result += 'Modified: ' + (meta.modifiedTime || '') + '\n';
      if (meta.webViewLink) result += 'View/Download: ' + meta.webViewLink + '\n';
      return [{ json: { result } }];
    }

    let result = '**' + meta.name + '**';
    if (exported) result += ' (exported from Google ' + mime.split('.').pop() + ')';
    result += '\nType: ' + mime + '\nModified: ' + (meta.modifiedTime || '') + '\n\n';

    if (content.length > 5000) {
      result += content.substring(0, 5000) + '\n\n... (truncated, ' + content.length + ' chars total)';
    } else {
      result += content;
    }
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Failed to read file: ' + e.message } }];
  }

// === create_file ===
} else if (action === 'create_file') {
  const name = input.name;
  const content = input.content;
  if (!name || !content) return [{ json: { error: 'Parameters "name" and "content" are required.' } }];

  const isDoc = input.mime_type === 'doc';
  const fileMime = isDoc ? 'application/vnd.google-apps.document' : 'text/plain';

  try {
    const boundary = 'n8n_boundary_' + Date.now();
    const metadata = { name: name, mimeType: fileMime };
    if (input.folder_id) metadata.parents = [input.folder_id];

    const body = '--' + boundary + '\r\n'
      + 'Content-Type: application/json; charset=UTF-8\r\n\r\n'
      + JSON.stringify(metadata) + '\r\n'
      + '--' + boundary + '\r\n'
      + 'Content-Type: text/plain; charset=UTF-8\r\n\r\n'
      + content + '\r\n'
      + '--' + boundary + '--';

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,mimeType,webViewLink',
      headers: {
        'Authorization': 'Bearer ' + accessToken,
        'Content-Type': 'multipart/related; boundary=' + boundary
      },
      body: body
    });

    let result = 'File created successfully:\n';
    result += 'Name: ' + resp.name + '\n';
    result += 'ID: ' + resp.id + '\n';
    result += 'Type: ' + resp.mimeType + '\n';
    if (resp.webViewLink) result += 'Link: ' + resp.webViewLink + '\n';
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Failed to create file: ' + e.message } }];
  }

// === create_folder ===
} else if (action === 'create_folder') {
  const name = input.name;
  if (!name) return [{ json: { error: 'Parameter "name" is required.' } }];

  try {
    const metadata = {
      name: name,
      mimeType: 'application/vnd.google-apps.folder'
    };
    if (input.parent_folder_id) metadata.parents = [input.parent_folder_id];

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: DRIVE_BASE + '/files?fields=id,name,mimeType,webViewLink',
      headers: gHeaders,
      body: JSON.stringify(metadata)
    });

    let result = 'Folder created successfully:\n';
    result += 'Name: ' + resp.name + '\n';
    result += 'ID: ' + resp.id + '\n';
    if (resp.webViewLink) result += 'Link: ' + resp.webViewLink + '\n';
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Failed to create folder: ' + e.message } }];
  }

// === delete_file ===
} else if (action === 'delete_file') {
  const fileId = input.file_id;
  if (!fileId) return [{ json: { error: 'Parameter "file_id" is required.' } }];

  try {
    // Get name first for confirmation message
    const meta = await helpers.httpRequest({
      method: 'GET',
      url: DRIVE_BASE + '/files/' + fileId + '?fields=name,mimeType',
      headers: gHeaders
    });

    await helpers.httpRequest({
      method: 'DELETE',
      url: DRIVE_BASE + '/files/' + fileId,
      headers: gHeaders
    });

    const type = meta.mimeType === 'application/vnd.google-apps.folder' ? 'Folder' : 'File';
    return [{ json: { result: type + ' "' + meta.name + '" deleted successfully.' } }];
  } catch(e) {
    return [{ json: { error: 'Failed to delete: ' + e.message } }];
  }

// === share_file ===
} else if (action === 'share_file') {
  const fileId = input.file_id;
  if (!fileId) return [{ json: { error: 'Parameter "file_id" is required.' } }];

  const shareType = input.type || 'user';
  const role = input.role || 'reader';

  if (shareType === 'user' && !input.email) {
    return [{ json: { error: 'Parameter "email" is required when type is "user".' } }];
  }

  try {
    const permission = { role: role, type: shareType };
    if (shareType === 'user') permission.emailAddress = input.email;

    await helpers.httpRequest({
      method: 'POST',
      url: DRIVE_BASE + '/files/' + fileId + '/permissions',
      headers: gHeaders,
      body: JSON.stringify(permission)
    });

    // Get file name for confirmation
    const meta = await helpers.httpRequest({
      method: 'GET',
      url: DRIVE_BASE + '/files/' + fileId + '?fields=name,webViewLink',
      headers: gHeaders
    });

    let result = 'File "' + meta.name + '" shared successfully.\n';
    result += 'Role: ' + role + '\n';
    if (shareType === 'user') result += 'Shared with: ' + input.email + '\n';
    if (shareType === 'anyone') result += 'Shared publicly (anyone with the link)\n';
    if (meta.webViewLink) result += 'Link: ' + meta.webViewLink + '\n';
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Failed to share file: ' + e.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: list_files, search_files, read_file, create_file, create_folder, delete_file, share_file.' } }];
}
